head.script:
/*
 * 화 면 명 : 거래처정보관리
 * 메뉴경로 : 엔콜/기초자료/거래처관리
 * ASIS경로 : /dongwon-ntis-engine/src/main/webapp/bp/fbp/bi/cm/ez_112_01_01b.jsp
 * 작 성 자 : 유청아
 * 작 업 일 : 2026-03-18
 * 참고사항 : 1. 협력사 계정으로 로그인(pjk1030/1111)
 *           2. [입력창 닫기] 버튼 삭제 : TOBE에서는 입력영역을 처음부터 보이게 하기로 함
 *           3. ASIS는 신규일때 담당자, 사업자 탭만 보이고 수정일때 나머지 탭이 보이는데 TOBE에서는 처음부터 탭이 보이므로 비활성 처리되는걸로 협의함(박주령PM)
 *           4. 자회사용 udc_commonCombo, udc_common_textbox 사용됨
 *           5. 계좌정보 탭에서 dataList의 row가 없을때 은행명 콤보박스가 선택이 안되므로 처리로직이 ASIS와 조금 다름
 *           6. ASIS와 동작이 달라도 개선된 사항은 결함이 아님(포맷이나 오류나는 부분 개선함)
 */

scwin.rowPos = 0; // 그리드 현재 위치

//-------------------------------------------------------------------------
// 화면 로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    tac_tabControl1.hideTab(2);
    tac_tabControl1.hideTab(3);
    tac_tabControl1.hideTab(4);
    tac_tabControl1.hideTab(5);
    tac_tabControl1.hideTab(6);    
};

//-------------------------------------------------------------------------
// UDC Completed
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {    
    dma_cond.set("all", "0");
    $p.setTimeout(function () {
        // 조회
        scwin.RetriveOfClient()
    }, { "delay": 200 });

    //팝업인 경우 
    if ($p.top().$p.isPopup()){
        grd_section1.addClass("gvwflex");
    }
};

//-------------------------------------------------------------------------
// 운임추가, 월대추가 버튼 클릭 시 해당 영역 visible 처리
//-------------------------------------------------------------------------
scwin.reWindLayer = function (str) {
    //apDiv10 : 구간단가 추가영역
    //apDiv11 : 월대금액 추가영역
    $c.data.undoAll(ds_PosFare);
    $c.data.undoAll(ds_FixCost);

    if (str == '10') {
        if (grp_tabs4_sub.getStyle("display") == 'none') {
            grp_main.setSize(null, 250);
            grp_tabs4_sub.show();
            grp_tabs7_sub.hide();
        } else {
            grp_tabs4_sub.hide();
            grp_tabs7_sub.hide();
            grp_main.setSize(null, null);
        }
    } else if (str == '11') {
        if (grp_tabs7_sub.getStyle("display") == 'none') {
            grp_main.setSize(null, 250);
            grp_tabs4_sub.hide();
            grp_tabs7_sub.show();
        } else {
            grp_tabs4_sub.hide();
            grp_tabs7_sub.hide();
            grp_main.setSize(null, null);
        }
    } else if (str == 'off') {
        grp_tabs4_sub.hide();
        grp_tabs7_sub.hide();
        grp_main.setSize(null, null);
    }
};

//-------------------------------------------------------------------------
// 계좌정보 조회
//-------------------------------------------------------------------------
scwin.RetrieveAccount = async function () {
    ds_Account.setJSON([]);
    dma_cond2.set("ez112Idx", ds_ClntMaster.getCellData(ds_ClntMaster.getRowPosition(), 'ez112Idx'));
    await $c.sbm.execute(sbm_RetrieveAccount);

    if (ds_Account.getRowCount() > 0) {
        gr_bankacc.setFocusedCell(0, "bankNm", false);
    }

    tbx_totalRows3.setValue(ds_Account.getRowCount());
};

//-------------------------------------------------------------------------
// 구간단가 조회
//-------------------------------------------------------------------------
scwin.RetrievePosFare = async function () {
    ds_PosFare.setJSON([]);
    dma_cond2.set("ez112Idx", ds_ClntMaster.getCellData(ds_ClntMaster.getRowPosition(), 'ez112Idx'));
    await $c.sbm.execute(sbm_RetrievePosFare);

    if (ds_PosFare.getRowCount() > 0) {
        ds_PosFare.setRowPosition(0);
        gr_PosFare.setFocusedCell(0, "col1", false);
    }

    tbx_totalRows4.setValue(ds_PosFare.getRowCount());
};

