    dma_cond2.set("ez112Idx", ds_ClntMaster.getCellData(ds_ClntMaster.getRowPosition(), 'ez112Idx'));
    await $c.sbm.execute(sbm_RetrieveItemFare);

    if (ds_ItemFare.getRowCount() > 0) {
        gr_ItemFare.setFocusedCell(0, "goods", false);
    }

    tbx_totalRows5.setValue(ds_ItemFare.getRowCount());
};

//-------------------------------------------------------------------------
// 조합단가 조회
//------------------------------------------------------------------------
scwin.RetrieveUnionFare = async function () {
    ds_UnionFare.setJSON([]);
    dma_cond2.set("ez112Idx", ds_ClntMaster.getCellData(ds_ClntMaster.getRowPosition(), 'ez112Idx'));
    await $c.sbm.execute(sbm_RetrieveUnionFare);

    if (ds_UnionFare.getRowCount() > 0) {
        gr_UnionFare.setFocusedCell(0, "onPosNm", false);
    }

    tbx_totalRows6.setValue(ds_UnionFare.getRowCount());
};

//-------------------------------------------------------------------------
// 월대금액 조회
//-------------------------------------------------------------------------
scwin.RetrieveFixCost = async function () {
    ds_FixCost.setJSON([]);
    dma_cond2.set("ez112Idx", ds_ClntMaster.getCellData(ds_ClntMaster.getRowPosition(), 'ez112Idx'));
    await $c.sbm.execute(sbm_RetrieveFixCost);

    if (ds_FixCost.getRowCount() > 0) {
        gr_FixCost.setFocusedCell(0, "fixCstCsstNm", false);
    }

    tbx_totalRows7.setValue(ds_FixCost.getRowCount());
};

//-------------------------------------------------------------------------
// 신규등록 버튼 클릭
//-------------------------------------------------------------------------
scwin.newinput = function () {
    ds_Account.setJSON([]);
    ds_FixCost.setJSON([]);
    ds_ItemFare.setJSON([]);
    ds_PosFare.setJSON([]);
    ds_UnionFare.setJSON([]);

    tac_tabControl1.hideTab(2);
    tac_tabControl1.hideTab(3);
    tac_tabControl1.hideTab(4);
    tac_tabControl1.hideTab(5);
    tac_tabControl1.hideTab(6);

    tac_tabControl1.setSelectedTabIndex(0);

    // insert시 클리어 안되서 수동으로 SET
    udc_coDtlAddr.setValue(""); //주소
    udc_dtlAddr.setValue(""); //dm주소

    ed_reqCloseDd.setValue("0"); //마감일

    if (ds_ClntMaster.getRowCount() == 0) {
        let rowIdx = $c.data.insertRow(gr_ClntMaster);        
        ds_ClntMaster.setRowJSON(
            rowIdx, 
            {
                "hdofficeIdx": ds_hiddenMap.get("hdoIdx"),
                "bhofficeIdx": ds_hiddenMap.get("bhoIdx"),
                "officeIdx": ds_hiddenMap.get("offIdx")
            },            
            true);

        grpInput.setDisabled(false);

    } else {
        var chk = 0;
        for (var i = 0; i < ds_ClntMaster.getRowCount(); i++) {
            if (ds_ClntMaster.getRowStatus(i) == "C") {
                chk++;
            }
        }
        if (chk > 0) {
            $c.win.alert("새로운 거래처정보는 저장 후 다시 추가해주세요.");
        } else {
            let rowIdx = $c.data.insertRow(gr_ClntMaster);      
            ds_ClntMaster.setRowJSON(
                rowIdx, 
                {
                    "hdofficeIdx": ds_hiddenMap.get("hdoIdx"),
                    "bhofficeIdx": ds_hiddenMap.get("bhoIdx"),
                    "officeIdx": ds_hiddenMap.get("offIdx")
                },            
                true);

            grpInput.setDisabled(false);
        }
    }
};

//-------------------------------------------------------------------------
// 계좌정보 - 신규 버튼 클릭
//-------------------------------------------------------------------------
scwin.addAccount = function () {
    if (ds_ClntMaster.getRowStatus(ds_ClntMaster.getRowPosition()) == "C") {
        $c.win.alert("거래처정보를 저장하신 후에 입력하실수 있습니다.");
    } else {
        if (ds_Account.getRowCount() > 0) {
            if (ds_Account.getCellData(ds_Account.getRowPosition(), 'bankCd') == "") {
                $c.win.alert("은행을 선택해주세요.");
                return;
            } else if (ds_Account.getCellData(ds_Account.getRowPosition(), 'bankAcntNo') == "") {
                $c.win.alert("계좌번호를 입력해주세요.");
                return;
            } else if (ds_Account.getCellData(ds_Account.getRowPosition(), 'bankAcntNo') == "") {
                $c.win.alert("예금주를 입력해주세요.");
                return;
            } 
        } 

        $c.data.insertRow(gr_bankacc);
        ds_Account.setCellData(ds_Account.getRowPosition(), 'ez112Idx', ds_ClntMaster.getCellData(ds_ClntMaster.getRowPosition(), 'ez112Idx'));
    }
};

