//-------------------------------------------------------------------------
// 삭제하기 버튼 클릭
//-------------------------------------------------------------------------
scwin.deletethis = async function () {
    if (ds_ClntMaster.getRowCount() == 0) { // TOBE : 로직 추가
        $c.win.alert("삭제할 거래처정보를 선택해주세요.");
    }

    let ret = await $c.win.confirm("삭제하시겠습니까?");
    if (ret) {
        if (ds_ClntMaster.getRowStatus(ds_ClntMaster.getRowPosition()) == "C") {
            ds_ClntMaster.removeRow(ds_ClntMaster.getRowPosition())

            if (ds_ClntMaster.getRowCount() == 0 || ds_ClntMaster.getRowStatus(ds_ClntMaster.getRowPosition()) == "C") {
                tac_tabControl1.hideTab(2);
                tac_tabControl1.hideTab(3);
                tac_tabControl1.hideTab(4);
                tac_tabControl1.hideTab(5);
                tac_tabControl1.hideTab(6);

                tac_tabControl1.setSelectedTabIndex(0);
            } else {
                tac_tabControl1.showTab(2);
                tac_tabControl1.showTab(3);
                tac_tabControl1.showTab(4);
                tac_tabControl1.showTab(5);
                tac_tabControl1.showTab(6);
            }
        } else {
            ds_del.setJSON([]);
            ds_del.insertRow();
            var bizcond = ds_ClntMaster.getCellData(ds_ClntMaster.getRowPosition(), 'ez112Idx');
            ds_del.setCellData(0, 'bizcond', bizcond);
            ds_Result.removeAll();
            ds_Result.reform();
            $c.sbm.execute(sbm_delete);
        }
    }
};

