//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.savethis = function () {
    if (ds_ClntMaster.getRowCount() == 0) {
        $c.win.alert("신규등록 버튼을 눌러서 정보를 입력 해주세요.");
        return false;
    }
    if (ds_ClntMaster.getCellData(ds_ClntMaster.getRowPosition(), 'ez106Idx') == "") {
        $c.win.alert("사업소구분을 선택해주세요.");
        return false;
    } else if (ds_ClntMaster.getCellData(ds_ClntMaster.getRowPosition(), 'clntCls') == "") {
        $c.win.alert("분류를 선택해주세요.");
        return false;
    } else if (ds_ClntMaster.getCellData(ds_ClntMaster.getRowPosition(), 'cmpyKor') == "") {
        $c.win.alert("상호를 입력해주세요.");
        return false;
    } else if (ds_ClntMaster.getCellData(ds_ClntMaster.getRowPosition(), 'picNm') == "") {
        $c.win.alert("담당자명을 입력해주세요.");
        return false;
    } else if ((ds_ClntMaster.getCellData(ds_ClntMaster.getRowPosition(), 'repstNm') != "") || (ds_ClntMaster.getCellData(ds_ClntMaster.getRowPosition(), 'bizcond') != "") || (ds_ClntMaster.getCellData(ds_ClntMaster.getRowPosition(), 'catBusi') != "")) {
        if (ds_ClntMaster.getCellData(ds_ClntMaster.getRowPosition(), 'crnNo') == "") {
            $c.win.alert("사업자번호를 입력해주세요.");
            return false;
        }
    }

    $c.sbm.execute(sbm_SaveClntMaster);

    scwin.rowPos = ds_ClntMaster.getRowPosition();
};

//-------------------------------------------------------------------------
// 계좌정보 - 저장 버튼 클릭
//-------------------------------------------------------------------------
scwin.saveAccount = function () {
    if (ds_Account.getRowCount() > 0) {
        if (ds_Account.getCellData(ds_Account.getRowCount() - 1, 'bankCd') == "") {
            $c.win.alert("은행을 선택해주세요.");
        } else if (ds_Account.getCellData(ds_Account.getRowCount() - 1, 'bankAcntNo') == "") {
            $c.win.alert("계좌번호를 입력해주세요.");
        } else if (ds_Account.getCellData(ds_Account.getRowCount() - 1, 'bankAcntNo') == "") {
            $c.win.alert("예금주를 입력해주세요.");
        } else {
            $c.sbm.execute(sbm_SaveAccount);
        }
    } else {
        $c.win.alert("신규버튼을 클릭하신 후 데이터를 입력해주세요");
    }
};

