//-------------------------------------------------------------------------
// 검색 텍스트 엔터키
//-------------------------------------------------------------------------
scwin.ed_STEXT_onkeydown = function (e) {
    if (e.keyCode == 13) {
        scwin.RetriveOfClient();
    }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.RetriveOfClient = function () {
    if (acb_STYPE.getSelectedIndex() == 0) {
        ds_ClntMaster.setJSON([]);

        $c.sbm.execute(sbm_retrive);
    } else if (acb_STYPE.getSelectedIndex() != 0 && ed_STEXT.getValue() != "") {
        ds_ClntMaster.setJSON([]);

        $c.sbm.execute(sbm_retrive);
    } else {
        $c.win.alert("조회조건이 입력되지 않았습니다.");
    }
};

//-------------------------------------------------------------------------
// 분할 체크박스 선택시 분할금액, 분할횟수 계산
//-------------------------------------------------------------------------
scwin.calcDivs = function () {
    if (cbx_divsYn.getValue() == true) {
        ds_FixCost.setCellData(ds_FixCost.getRowPosition(), 'divsYn', 1);
        var levyAmt = ed_levyAmt.getValue().trim();
        var divsCnt = 0;
        var levyDd = ed_levyDd.getValue().trim();
        var divsAmt = 0;

        var levyStDd = ica_levyStDd.getValue().trim();
        var levyStY = levyStDd.substring(0, 4);
        var levyStM = levyStDd.substring(4, 6);
        var levyStD = levyStDd.substring(6, 8);

        var levyEndDd = ica_levyEndDd.getValue().trim();
        var levyEndY = levyEndDd.substring(0, 4);
        var levyEndM = levyEndDd.substring(4, 6);
        var levyEndD = levyEndDd.substring(6, 8);

        divsCnt = (levyEndY - levyStY) * 12;
        divsCnt += levyEndM - levyStM - 1;
        if (levyStD < levyDd) { divsCnt++; }
        if (levyEndD > levyDd) { divsCnt++; }

        // 0으로 나누면 ASIS는 오류인데도 1이 되기 때문에 로직 추가
        if (divsCnt == 0) {
            divsAmt = 1;
        } else {
            divsAmt = parseInt(levyAmt) / parseInt(divsCnt);
        }        

        ed_divsCnt.setValue(divsCnt);
        ed_divsAmt.setValue(divsAmt);
    } else {
        ds_FixCost.setCellData(ds_FixCost.getRowPosition(), 'divsYn', 0);
        ed_divsCnt.setValue("");
        ed_divsAmt.setValue("");
    }
}

//-------------------------------------------------------------------------
// 입력 시 dataList RowCount 체크
//-------------------------------------------------------------------------
scwin.preCheck = function (ds) {
    const dltObj = $c.gus.object(ds);

    if (dltObj.getRowCount() == 0) {
        $c.win.alert("신규버튼을 누른 후 입력해주세요.");
    }
};

//-------------------------------------------------------------------------
// 사업자번호 체크
//-------------------------------------------------------------------------
scwin.isBusiNoByValue = async function () {    
    strNo = ed_crnNo.getValue();

    if (strNo != "") {
        var sum = 0;
        var getlist = new Array(10);
        var chkvalue = new Array("1", "3", "7", "1", "3", "7", "1", "3", "5");

        for (var i = 0; i < 10; i++) {
            getlist[i] = strNo.substring(i, i + 1);
        }

        for (var i = 0; i < 9; i++) {
            sum += getlist[i] * chkvalue[i];
        }

        sum = sum + parseInt((getlist[8] * 5) / 10);
        sidliy = sum % 10;
        sidchk = 0;

        if (sidliy != 0) {
            sidchk = 10 - sidliy;
        } else {
            sidchk = 0;
        }

        if (sidchk != getlist[9]) {            
            await $c.win.alert("유효하지 않은 사업자번호입니다.");
            ed_crnNo.focus();
        }
    }

    return true;
}

//-------------------------------------------------------------------------
// 조회 submitdone
//-------------------------------------------------------------------------
scwin.sbm_retrive_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    if (ds_ClntMaster.getRowCount() == 0) {
        grpInput.setDisabled(true);
        $c.win.alert("조회결과가 없습니다.");

        tac_tabControl1.hideTab(2);
        tac_tabControl1.hideTab(3);
        tac_tabControl1.hideTab(4);
        tac_tabControl1.hideTab(5);
        tac_tabControl1.hideTab(6);

    } else {
        grpInput.setDisabled(false);
        tac_tabControl1.showTab(2);
        tac_tabControl1.showTab(3);
        tac_tabControl1.showTab(4);
        tac_tabControl1.showTab(5);
        tac_tabControl1.showTab(6);

        if (scwin.rowPos > 0) {
            gr_ClntMaster.setFocusedCell(scwin.rowPos, "clntCls", false);
        } else {
            gr_ClntMaster.setFocusedCell(0, "clntCls", false);
            scwin.rowPos = 0;
        }

        // 자동 바인딩 안되서 수동으로 SET
        udc_coDtlAddr.setValue(ds_ClntMaster.getCellData(ds_ClntMaster.getRowPosition(), "coDtlAddr")); //주소
        udc_dtlAddr.setValue(ds_ClntMaster.getCellData(ds_ClntMaster.getRowPosition(), "dtlAddr")); //dm주소
    }

    tbx_totalRows.setValue(ds_ClntMaster.getRowCount());
};


