//-------------------------------------------------------------------------
// 탭 변경
//-------------------------------------------------------------------------
scwin.tac_tabControl1_onchange = function (tabId, index, userTabId) {
    scwin.reWindLayer('off');

    if (index == 2) { // 계좌정보
        scwin.RetrieveAccount();
    } else if (index == 3) { // 구간단가
        scwin.RetrievePosFare();
    } else if (index == 4) { // 화물단가
        scwin.RetrieveItemFare();
    } else if (index == 5) { // 조합단가
        scwin.RetrieveUnionFare();
    } else if (index == 6) { // 월대금액
        scwin.RetrieveFixCost();
    }
};

